using FluentAssertions;
using FluentAssertions.Execution;

using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Options;

using Quartz.Simpl;

namespace Quartz.Tests.Unit.Simpl;

public class MicrosoftDependencyInjectionJobFactoryTest
{
    [Test]
    [Ignore("WIP")]
    public void DisposedServiceProviderShouldThrowSchedulerException()
    {
        var factory = new MicrosoftDependencyInjectionJobFactory(new TestServiceProvider(), Options.Create(new QuartzOptions()));
        factory.NewJob(TestUtil.NewMinimalTriggerFiredBundle(), null!);
    }

    [Test]
    public async Task JobsShouldBeDisposedAfterExecute()
    {
        var schedulerBuilder = SchedulerBuilder.Create()
            .Build();

        const string testValue = "test";

        var jobDetail = JobBuilder.Create<TestJob>()
            .StoreDurably()
            .UsingJobData(nameof(TestJob.Test), testValue)
            .Build();

        var serviceCollection = new ServiceCollection();
        serviceCollection.AddTransient<TestJob>();
        serviceCollection.AddTransient<Dependency>();
        var serviceProvider = serviceCollection.BuildServiceProvider(validateScopes: true);

        var scheduler = await schedulerBuilder.GetScheduler();
        scheduler.JobFactory = new MicrosoftDependencyInjectionJobFactory(serviceProvider, Options.Create(new QuartzOptions()));
        await scheduler.Start();

        await scheduler.AddJob(jobDetail, replace: false);
        await scheduler.TriggerJob(jobDetail.Key);

        await Task.Delay(100);
        using (new AssertionScope())
        {
            TestJob.Executed.Should().BeTrue();
            TestJob.Disposed.Should().BeTrue();
            TestJob.TestValue.Should().Be(testValue);

            Dependency.Disposed.Should().BeTrue();
        }
    }

    [Test]
    public async Task JobShouldExecuteWithAsyncLocalValuesConfiguredByJobFactory()
    {
        const string testValue = "test";

        static async Task<IJob> CreateJob(MicrosoftDependencyInjectionJobFactory factory, TriggerFiredBundle bundle, IScheduler scheduler)
        {
            var job = factory.NewJob(bundle, scheduler);
            await Task.Yield();
            return job;
        }

        var serviceCollection = new ServiceCollection();
        serviceCollection.AddTransient<AsyncLocalJob>();
        await using var serviceProvider = serviceCollection.BuildServiceProvider(validateScopes: true);

        var scheduler = await SchedulerBuilder.Create().Build().GetScheduler();
        var bundle = TestUtil.NewMinimalTriggerFiredBundle(typeof(AsyncLocalJob));
        bundle.JobDetail.JobDataMap.Put(AsyncLocalJob.TestDataMapKey, testValue);

        var factory = new AsyncLocalJobFactory(serviceProvider, Options.Create(new QuartzOptions()));
        var job = await CreateJob(factory, bundle, scheduler);

        await job.Execute(null!);

        AsyncLocalJob.ExecutedValue.Should().Be(testValue);
    }

    private sealed class AsyncLocalJobFactory : MicrosoftDependencyInjectionJobFactory
    {
        public AsyncLocalJobFactory(IServiceProvider serviceProvider, IOptions<QuartzOptions> options) : base(serviceProvider, options)
        {
        }

        public override void SetObjectProperties(object obj, JobDataMap data)
        {
            base.SetObjectProperties(obj, data);
            AsyncLocalJob.Value.Value = data.GetString(AsyncLocalJob.TestDataMapKey);
        }
    }

    private sealed class AsyncLocalJob : IJob
    {
        public const string TestDataMapKey = "Test";
        public static readonly AsyncLocal<string> Value = new();
        public static string? ExecutedValue { get; private set; }

        public ValueTask Execute(IJobExecutionContext context)
        {
            ExecutedValue = Value.Value;
            return default;
        }
    }

    private class TestJob : IJob, IDisposable
    {
        public static bool Executed { get; set; }
        public static bool Disposed { get; set; }
        public static string TestValue { get; set; }

        public string Test { get; set; }

        public TestJob(Dependency dependency)
        {
        }

        public ValueTask Execute(IJobExecutionContext context)
        {
            Executed = true;
            TestValue = Test;
            return new ValueTask();
        }

        public void Dispose()
        {
            Disposed = true;
        }
    }

    private sealed class Dependency : IDisposable
    {
        public static bool Disposed { get; set; }

        public void Dispose()
        {
            Disposed = true;
        }
    }

    private class TestServiceProvider : IServiceProvider
    {
        public object GetService(Type serviceType)
        {
            return Activator.CreateInstance(serviceType);
        }
    }
}

