                return Target.Execute(context);
            }

            return ExecuteInCapturedContext(context, executionContext);
        }

        private ValueTask ExecuteInCapturedContext(IJobExecutionContext context, ExecutionContext executionContext)
        {
            ValueTask result = default;
            Exception? exception = null;

            ExecutionContext.Run(executionContext.CreateCopy(), _ =>
            {
